mapper.sql:
SELECT ID
HQ_DATA_ID
TALLY_ID
UPDATE_INFO
CREATE_BY
CREATE_BY_NAME
CREATE_TIME
FROM M_HQ_DATA_LOG
and ID = #{id}
and HQ_DATA_ID = #{hqDataId}
and TALLY_ID = #{tallyId}
and UPDATE_INFO = #{updateInfo}

mapper.insert:
INSERT INTO M_HQ_DATA_LOG( ID, HQ_DATA_ID, TALLY_ID, UPDATE_INFO, CREATE_BY, CREATE_BY_NAME, CREATE_TIME ) (
SELECT #{item.id}, #{item.hqDataId}, #{item.tallyId}, #{item.updateInfo}, #{item.createBy, jdbcType=BIGINT}, #{item.createByName, jdbcType=VARCHAR}, #{item.createTime} from dual
)
